import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge case: empty items ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (with first insurance applied per item; assume newcomer 0 yrs) ---
  it("single sword (plain, newcomer) → 100 base + 10 first insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet (plain, newcomer) → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff (plain, newcomer) → 80 + 8 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion (plain, newcomer) → 40 + 4 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // --- Components: runes and moonstones ---
  it("2 runes → 50 G base + 5 first insurance + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes → 60 G base (block) + 6 first ins + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (no block — 7 is not exactly 3)");

  // --- 'Alike' components clarification ---
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Item-specific modifiers (no policy-wide modifiers besides first insurance) ---
  it.todo("cursed sword (newcomer) → 100 + 50 curse + 10 first insurance + 5 fee = 165 G");
  it.todo("sword with enchantment 5 → high-enchantment surcharge applies (100 + 30 + 10 + 5 = 145)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 + 10 + 5 = 115)");
  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 10 + 5 = 195)");

  // --- Modifier scope: cursed applies only to the cursed item in a multi-item policy ---
  it.todo("cursed sword + plain amulet (newcomer): item bases 100+60=160; curse 50 (on sword only); first ins 21 (10% of 210); +5 fee = 236 G");

  // --- Policy-wide modifiers ---
  it.todo("long-standing customer (exactly 2 years) with plain sword: 100 base - 20 loyalty + 10 first insurance + 5 fee = 95 G");
  it.todo("customer's second quote (plain sword): 100 + 10 first insurance - 15 follow-up + 5 fee = 100 G");

  // --- Integration examples ---
  it.todo("Newcomer with cursed sword (steel, ench 3): premium 165 G");
  it.todo("Long-standing customer (3 yrs) second contract, cursed sword (steel, ench 7): premium 160 G");
  it.todo("first insurance surcharge applies to each item even for follow-up contract");

  // --- Rounding in MHPCO favor ---
  it.todo("premium yielding 197.5 G → 198 G (rounded up)");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");

  // --- Claim: high enchantment clause ---
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material clause ---
  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: dragon precedence over high enchantment ---
  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins per spec interpretation: 500-100)");
  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G");

  // --- Claim: rounding payout down ---
  it.todo("payout yielding 350.5 G → 350 G (rounded down)");

  // --- Claim: deductible per damage event (per damaged item) ---
  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout = 600 G (100 deductible per item)");

  // --- Claim: multiple items of same type ---
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
  it.todo("policy with two swords; damages array with two sword entries → each gets own deductible");
  it.todo("damages array contains more entries of a type than policy covers → CLI exits non-zero, claim rejected");

  // --- Claim: cap ---
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium with mods 165) → cap 2000 G (based on unmodified insurance value)");
  it.todo("policy covers sword + 3 runes → insurance sum 1750 G (block doesn't affect insurance sum)");
  it.todo("sword cap 2000: first claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");

  // --- Error cases ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results");
  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim with negative damage amount (-200) → CLI exits non-zero, error to stderr");

  // --- CLI integration ---
  it.todo("CLI: end-to-end scenario with quote + claim produces results array of correct length and shape");
});

