const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);

const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const payoutForDamage = (amount: number): number => amount - DEDUCTIBLE;

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policyItems: Item[][] = [];
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const premium = quotePremium(step.items, scenario.customer, quoteCount);
      quoteCount += 1;
      policyItems.push(step.items);
      return { premium };
    }
    const items = policyItems[step.policy];
    const cap = insuranceSum(items) * CAP_MULTIPLIER;
    const payout = step.incident.damages.reduce(
      (sum, damage) => sum + payoutForDamage(damage.amount),
      0,
    );
    return { payout, remainingCap: cap - payout };
  });
  return { results };
};

