const claimResult = (incident: Incident, policyItems: Item[], availableCap: number): ClaimResult => {
  const desiredPayout = roundPayoutInMHPCOFavor(totalPayout(incident.damages, policyItems));
  const payout = Math.min(desiredPayout, availableCap);
  return { payout, remainingCap: availableCap - payout };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
