const countByType = <T extends { type?: string; itemType?: string }>(
  entries: T[],
  key: (e: T) => string,
): Record<string, number> =>
  entries.reduce<Record<string, number>>((counts, entry) => {
    const k = key(entry);
    counts[k] = (counts[k] ?? 0) + 1;
    return counts;
  }, {});

const validateDamagesAgainstPolicy = (damages: Damage[], items: Item[]): void => {
  const insuredCounts = countByType(items, (i) => i.type);
  const damageCounts = countByType(damages, (d) => d.itemType);
  for (const [type, count] of Object.entries(damageCounts)) {
    if (count > (insuredCounts[type] ?? 0)) {
      throw new Error(`damages contain ${count} entries for "${type}" but policy covers only ${insuredCounts[type] ?? 0}`);
    }
  }
};

const claimAgainst = (policy: Policy, incident: Incident): ClaimResult => {
  validateDamagesAgainstPolicy(incident.damages, policy.items);
  const desiredPayout = roundPayoutInMHPCOFavor(totalPayout(incident.damages, policy.items));
  const payout = Math.min(desiredPayout, policy.remainingCap);
  return { payout, remainingCap: policy.remainingCap - payout };
};

